#define THREADS 256

inline int mirror_index(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    if (d >= sizeD) {
        d = 2 * sizeD - 2 - d;
    } else if (d < 0) {
        d = -d;
    }
    if (d < 0) d = 0;
    if (d >= sizeD) d = sizeD - 1;
    return d;
}

inline int src_at(__global const int *in, int sx, int sy, int x, int y)
{
    x = mirror_index(x, sx);
    y = mirror_index(y, sy);
    return in[y * sx + x];
}

inline int h_odd(__global const int *in, int sx, int sy, int y, int x_odd)
{
    int c = src_at(in, sx, sy, x_odd, y);
    int p = src_at(in, sx, sy, x_odd - 1, y);
    int n = src_at(in, sx, sy, x_odd + 1, y);
    return c - ((p + n) / 2);
}

inline int h_even(__global const int *in, int sx, int sy, int y, int x_even)
{
    int c = src_at(in, sx, sy, x_even, y);
    int p = h_odd(in, sx, sy, y, x_even - 1);
    int n = h_odd(in, sx, sy, y, x_even + 1);
    return c + ((p + n + 2) / 4);
}

inline int h_val(__global const int *in, int sx, int sy, int y, int x)
{
    return (x & 1) ? h_odd(in, sx, sy, y, x) : h_even(in, sx, sy, y, x);
}

inline int v_odd(__global const int *in, int sx, int sy, int y_odd, int x)
{
    int c = h_val(in, sx, sy, y_odd, x);
    int p = h_val(in, sx, sy, y_odd - 1, x);
    int n = h_val(in, sx, sy, y_odd + 1, x);
    return c - ((p + n) / 2);
}

inline int v_even(__global const int *in, int sx, int sy, int y_even, int x)
{
    int c = h_val(in, sx, sy, y_even, x);
    int p = v_odd(in, sx, sy, y_even - 1, x);
    int n = v_odd(in, sx, sy, y_even + 1, x);
    return c + ((p + n + 2) / 4);
}

inline int v_val(__global const int *in, int sx, int sy, int y, int x)
{
    return (y & 1) ? v_odd(in, sx, sy, y, x) : v_even(in, sx, sy, y, x);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid < pixels) {
        int o = gid * 3;
        d_r[gid] = ((int)d_src[o + 0]) - 128;
        d_g[gid] = ((int)d_src[o + 1]) - 128;
        d_b[gid] = ((int)d_src[o + 2]) - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid < pixels) {
        d_c[gid] = ((int)d_src[gid]) - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    const int g0 = (int)get_global_id(0);
    const int g1 = (int)get_global_id(1);
    const int gs0 = (int)get_global_size(0);
    const int gs1 = (int)get_global_size(1);

    const int totalThreads = gs0 * gs1;
    const int tid = g1 * gs0 + g0;
    const int total = sizeX * sizeY;

    const int llX = (sizeX + 1) >> 1;
    const int llY = (sizeY + 1) >> 1;
    const int hlX = sizeX - llX;
    const int lhY = sizeY - llY;

    const int offLL = 0;
    const int offHL = llX * llY;
    const int offLH = offHL + hlX * llY;
    const int offHH = offLH + llX * lhY;

    for (int idx = tid; idx < total; idx += totalThreads) {
        int x = idx % sizeX;
        int y = idx / sizeX;

        int coeff = v_val(input, sizeX, sizeY, y, x);

        int ox = x >> 1;
        int oy = y >> 1;
        int outIdx;

        if ((y & 1) == 0) {
            if ((x & 1) == 0) {
                outIdx = offLL + oy * llX + ox; // LL
            } else {
                outIdx = offHL + oy * hlX + ox; // HL
            }
        } else {
            if ((x & 1) == 0) {
                outIdx = offLH + oy * llX + ox; // LH
            } else {
                outIdx = offHH + oy * hlX + ox; // HH
            }
        }

        output[outIdx] = coeff;
    }
}
